mapper.select:
SELECT staff_id, user_id, name, gender, birth_date, origin, id_card, avatar, resume,
       bio, work_experience_text, professional_skills,
       work_experience, hourly_rate, rating, work_status, verification_status, create_time, update_time
FROM staff

    AND gender = #{gender}
    AND origin LIKE CONCAT('%', #{origin}, '%')
    AND rating >= #{minRating}
    AND work_experience >= #{minWorkExperience}
    AND verification_status = #{verificationStatus}

ORDER BY rating DESC, work_experience DESC

SELECT s.staff_id, s.user_id, s.name, s.gender, s.birth_date, s.origin, s.id_card, s.avatar, s.resume, s.bio, s.work_experience_text, s.professional_skills, s.work_experience, s.hourly_rate, s.rating, s.work_status, s.verification_status, s.create_time, s.update_time, u.phone, u.email FROM staff s LEFT JOIN user u ON s.user_id = u.user_id
AND s.verification_status = #{verificationStatus} AND s.work_status = #{workStatus}
ORDER BY s.rating DESC, s.work_experience DESC

mapper.update:
UPDATE staff
name = #{name}, gender = #{gender}, birth_date = #{birthDate}, origin = #{origin}, id_card = #{idCard}, avatar = #{avatar}, resume = #{resume}, bio = #{bio}, work_experience_text = #{workExperienceText}, professional_skills = #{professionalSkills}, work_experience = #{workExperience}, hourly_rate = #{hourlyRate}, rating = #{rating}, work_status = #{workStatus}, verification_status = #{verificationStatus},
WHERE staff_id = #{staffId}

UPDATE staff
SET verification_status = #{verificationStatus}
WHERE staff_id = #{staffId}
